payload.raw:
{
  "layout": "timeline",
  "title": "创新设计",
  "events": [
    {
      "date": "第1–2月",
      "title": "硬件攻坚阶段",
      "description": "完成柔性传感器微结构设计、液态金属-聚氨酯复合材料制备及信号标定，构建0.1mm级空间分辨率的混合传感架构。"
    },
    {
      "date": "第3月",
      "title": "算法开发阶段",
      "description": "开发分层CNN-LSTM手势识别模型与自适应滑动窗口分割模块，实现实测>98.2%的高鲁棒识别准确率，并搭建多模态融合协议栈。"
    },
    {
      "date": "第4月",
      "title": "系统集成阶段",
      "description": "完成软硬件联调，嵌入微型电磁致动器与半导体温控模块，构建感知-意图-反馈闭环，支持压力/温度微秒级精准调控。"
    },
    {
      "date": "第5–6月",
      "title": "场景验证优化阶段",
      "description": "依托H-Box全息舱与李未可眼镜等平台，在工业远程操控与虚拟实训场景开展压力测试，迭代优化用户体验并形成标准接口。"
    }
  ]
}

