payload.raw:
{
  "layout": "cards-3-featured",
  "title": "创新技术：自研高精度柔性传感器",
  "subtitle": "",
  "body": [
    {
      "type": "paragraph",
      "text": "通过材料、架构与系统级协同创新，实现高精度、低延迟、长寿命与低成本的统一，突破进口柔性传感器在医疗康复、智能穿戴等场景的性能与成本瓶颈。"
    }
  ],
  "cards": [
    {
      "icon": "target",
      "heading": "仿生材料体系",
      "body": "采用“水膜-鱼网”结构液态金属导电薄膜与低迟滞聚氨酯复合介质，构建高弹性导电网络，在拉伸应变下维持稳定电学性能，应变系数＞80。",
      "secondary": "经10万次弯折测试后性能衰减＜5%，循环寿命较传统方案提升3倍，显著增强器件耐久性与工程适用性。"
    },
    {
      "icon": "globe",
      "heading": "高精度感知应用",
      "body": "在动态手势识别与关节运动监测等实际场景中，实现0.1mm空间分辨率与＜50ms系统延迟，满足实时交互与精细控制需求。",
      "secondary": "相关成果发表于IEEE Transactions on Electron Devices（2023）及IEEE Sensors Journal（2024），获领域内学者引用验证其工程落地价值。"
    },
    {
      "icon": "code",
      "heading": "混合传感架构",
      "body": "融合光纤微形变检测与IMU姿态补偿算法，有效抑制单一传感模式下的信号漂移问题，提升长期测量稳定性与空间一致性。",
      "secondary": "相较纯电阻式或纯光学方案，系统综合成本降低超50%，同时关键性能指标达到或超越国际主流商用产品水平。"
    }
  ]
}

